import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { API_BASE_URL } from '../config';

const EventerRegister = () => {
  const navigate = useNavigate();

  const [eventerData, setEventerData] = useState({
    info: '',
    // 他の必要なフィールドをここに追加
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setEventerData({ ...eventerData, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const accountId = localStorage.getItem('account_id');
    try {
      const response = await fetch(`${API_BASE_URL}/eventer/register/${accountId}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(eventerData),
      });
      if (!response.ok) throw new Error('Eventer registration failed');
      // フォームをリセットまたは成功を処理
      setEventerData({ info: '' });
      navigate('/home'); // 必要に応じて遷移パスを調整
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <div>
      <h1>イベンター用のアカウント設定画面</h1>
    </div>
  );
};

export default EventerRegister;
